/**
 * Seed script for Tier 1 reference data.
 *
 * Seeds the most common current products with hardcoded data so the
 * reference database works even when TCDB scraping is unavailable.
 *
 * Products seeded:
 *   - 2026 Topps Series 1 (330 cards — 100 key cards)
 *   - 2025 Topps Series 1 (330 cards — FULL checklist)
 *   - 2025 Topps Series 2 (top 75 cards)
 *   - 2025 Bowman (50 base + 30 Chrome prospects)
 *   - 2025 Topps Chrome (top 50 cards)
 *   - 2024 Topps Series 1 (330 cards — top 50+ cards)
 *   - 2024 Topps Series 2 (top 75 cards)
 *   - 2024 Bowman (top 50 base + Chrome prospects)
 *   - 2024 Topps Chrome (top 50 cards)
 *   - 2023 Topps Series 1 (top 75 cards)
 *   - 2023 Topps Chrome (top 50 cards)
 *
 * Usage: npx tsx src/scripts/seed-checklists.ts
 */

// Load .env.local BEFORE any other imports via synchronous env injection
import { readFileSync } from "fs";
import { fileURLToPath } from "url";
import { dirname, resolve } from "path";

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

// Must run before any module that reads DATABASE_URL
const envPath = resolve(__dirname, "../../.env.local");
try {
  const envContent = readFileSync(envPath, "utf-8");
  for (const line of envContent.split("\n")) {
    const trimmed = line.trim();
    if (!trimmed || trimmed.startsWith("#")) continue;
    const eqIdx = trimmed.indexOf("=");
    if (eqIdx === -1) continue;
    const key = trimmed.substring(0, eqIdx).trim();
    const value = trimmed.substring(eqIdx + 1).trim();
    if (!process.env[key]) {
      process.env[key] = value;
    }
  }
  console.log("Loaded env from:", envPath, "DATABASE_URL set:", !!process.env.DATABASE_URL);
} catch (e) {
  console.warn("Could not load .env.local:", (e as Error).message);
}

// Dynamic imports AFTER env is loaded — ESM hoists static imports above all code
const { db, playerCanonical } = await import("@holdsworth/db");
const { eq } = await import("drizzle-orm");
const { seedProductData } = await import("../handlers/checklist-ingest");
const { log } = await import("../lib/logger");

