// ═══════════════════════════════════════════════════════════════════════════
// Main seed runner
// ═══════════════════════════════════════════════════════════════════════════

async function main() {
  console.log("╔══════════════════════════════════════╗");
  console.log("║   Holdsworth Reference Data Seeder   ║");
  console.log("╚══════════════════════════════════════╝");
  console.log("");

  const products = [
    { label: "2026 Topps Series 1", data: TOPPS_SERIES_1_2026 },
    { label: "2025 Topps Series 1", data: TOPPS_SERIES_1_2025 },
    { label: "2025 Topps Series 2", data: TOPPS_SERIES_2_2025 },
    { label: "2025 Bowman", data: BOWMAN_2025 },
    { label: "2025 Topps Chrome", data: TOPPS_CHROME_2025 },
    { label: "2024 Topps Series 1", data: TOPPS_SERIES_1_2024 },
    { label: "2024 Topps Series 2", data: TOPPS_SERIES_2_2024 },
    { label: "2024 Bowman", data: BOWMAN_2024 },
    { label: "2024 Topps Chrome", data: TOPPS_CHROME_2024 },
    { label: "2023 Topps Series 1", data: TOPPS_SERIES_1_2023 },
    { label: "2023 Topps Chrome", data: TOPPS_CHROME_2023 },
  ];

  for (const { label, data } of products) {
    log("seed", `Seeding ${label}...`);
    const result = await seedProductData(data);
    if (result.success) {
      log("seed", `${label}: ${result.cardsUpserted} cards, ${result.parallelsUpserted} parallels`);
    } else {
      console.error(`Failed to seed ${label}:`, result.error);
    }
  }

  // Seed player canonical data
  log("seed", "Seeding player canonical data...");
  let playersUpserted = 0;

  for (const player of PLAYER_CANONICAL_DATA) {
    const [existing] = await db
      .select()
      .from(playerCanonical)
      .where(eq(playerCanonical.canonicalName, player.canonicalName))
      .limit(1);

    if (existing) {
      await db
        .update(playerCanonical)
        .set({
          aliases: player.aliases,
          position: player.position,
          team: player.team,
          marketTier: player.marketTier,
          updatedAt: new Date(),
        })
        .where(eq(playerCanonical.id, existing.id));
    } else {
      await db
        .insert(playerCanonical)
        .values({
          canonicalName: player.canonicalName,
          aliases: player.aliases,
          sport: "baseball",
          position: player.position,
          team: player.team,
          marketTier: player.marketTier,
        });
    }
    playersUpserted++;
  }

  log("seed", `Player canonical: ${playersUpserted} players upserted`);

  console.log("");
  console.log("Seed complete!");
  console.log(`  Products: ${products.length}`);
  console.log(`  Players:  ${playersUpserted}`);
  process.exit(0);
}

main().catch((err) => {
  console.error("Seed script failed:", err);
  process.exit(1);
});
